query:
SELECT COUNT(*) as total_sellers FROM sellers;
SELECT COUNT(DISTINCT product_id) as products_with_sellers FROM sellers;
SELECT COUNT(*) as total_products FROM products;
SELECT s.facility_name, s.floor_info, s.shop_name, p.name as product_name, p.prefecture
FROM sellers s
JOIN products p ON s.product_id = p.id
LIMIT 10;

